// Classic round analog wall clock — replicad/BREP. One fused solid: the dial
// seats onto the back plate and every hand/marker/spindle overlaps the dial.
// Markers + hands stick ~1mm proud of the dial top (z=8) so paint can isolate
// them by z without dragging in the dial face.
const { BREP } = api;

const backPlateRaw = BREP.cylinder(40, 4);
const backPlate = BREP.label(
  backPlateRaw.chamfer(0.8, { maxZ: 0.01, parallelToPlane: 'XY' }),
  'back',
);

const bezel = BREP.label(BREP.torus(38, 4).translate([0, 0, 4]), 'bezel');

// Dial — 5mm thick from z=3: overlaps the back plate (z0..4) by 1mm, top z=8.
const dial = BREP.label(BREP.cylinder(34, 5).translate([0, 0, 3]), 'dial');

// Hour markers — z7..9, so 1mm stands proud of the dial top.
const markerSeed = BREP.label(BREP.box([1.5, 4, 2]).translate([0, 30, 7]), 'hour_marker');
const hourMarkers = BREP.circularPattern(markerSeed, 12, { radius: 0, axis: [0, 0, 1] });

// Hands — both axis-aligned (hour +Y, minute +X) so each is a clean box for
// painting; z7..9 overlaps the dial and stands 1mm proud.
const hourHand = BREP.label(BREP.box([2, 20, 2]).translate([0, 7, 7]), 'hour_hand');
const minuteHand = BREP.label(BREP.box([28, 1.2, 2]).translate([11, 0, 7]), 'minute_hand');

const spindle = BREP.label(BREP.cylinder(2, 3).translate([0, 0, 7]), 'spindle');

return BREP.fuseAll([
  backPlate, bezel, dial, hourMarkers, hourHand, minuteHand, spindle,
]);

